#include<bits/stdc++.h>
using namespace std;
int in[100010];
vector<int> mp[100010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,m;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
        {
            in[i]=0;
            mp[i].clear();
        }
        int flag=0;
        for(int i=1;i<=m;i++)
        {
            int u,v;
            scanf("%d%d",&v,&u);
            flag|=(u==v);
            mp[u].push_back(v);
            in[v]++;
        }
        if(flag)
        {
            printf("Impossible!\n");
            continue;
        }
        priority_queue<int> q;
        for(int i=1;i<=n;i++)
        {
            if(in[i]==0)
            {
                q.push(i);
            }
        }
        vector<int> ans;
        while(!q.empty())
        {
            int t=q.top();
            q.pop();
            ans.push_back(t);
            for(int i:mp[t])
            {
                in[i]--;
                if(in[i]==0)
                {
                    q.push(i);
                }
            }
        }
        if(ans.size()!=n)
        {
            printf("Impossible!\n");
        }
        else
        {
            reverse(ans.begin(),ans.end());
            for(int i:ans)
            {
                printf("%d ",i);
            }
            printf("\n");
        }
    }
    return 0;
}
